import React from 'react';

const AddCrop = () => {
  return (
    <div className="page-container p-6">
      <h1 className="text-2xl font-bold mb-4">Add Crop</h1>
      <p>Form to add new crops for sale or tracking goes here.</p>
    </div>
  );
};

export default AddCrop;
